assignments.value:
={{ (() => {
  const remitente = $item(0).$node["Webhook"].json.body.remitente || "";
  const destinatarios = $item(0).$node["Webhook"].json.body.destinatarios || "";
  const mensaje = $item(0).$node["Webhook"].json.body.mensaje || "";
  const archivo_url = $item(0).$node["Webhook"].json.body.archivo_url || "";

  let texto = "Remitente: " + remitente + "\n\nDestinatarios: " + destinatarios;

  if (mensaje.trim() !== "") {
    texto += "\n\nMensaje: " + mensaje;
  }

  if (archivo_url.trim() !== "") {
    texto += "\n\n📎 Archivo adjunto:\n" + archivo_url;
  }

  return texto;
})() }}
